%@LW_pgstart@@
<html>
  <head>
    <title>Trial Balance</title>
    <style>body {
        background-color: #fff;
      }
      th{
        background-color: #fff;
        color:#000;
        height: 10px;
      }
      .isi tr:nth-child(even){
        background-color : #ededed;
      }
      .customers tr:hover{
        background-color : #ddd;
      }

      table {
        border-collapse:collapse;
      }

      .isi table, .isi td, .isi th {
        border:1px solid black;
      	font-size:13px
      }
      #head  table, #head td, #head th{
        border:none !important; 
      }
      @media print
      { 
        table { page-break-inside:auto }
		tr    { page-break-inside:avoid; page-break-after:auto }
		thead { display:table-header-group }
		tfoot { display:table-footer-group } 

        .no-print, .no-print *
        {
          display: none !important;
        }
      	@page{
        	size: A4;
      	}
      }

    </style>
    <style>
      .text1{
        font-size: 10px;
      }
      .text2{
        font-size: 12px;
      }
    </style>
  </head>
  <body bgcolor="#ffffff" text="#000" style="font-family:arial;">

    LW_pgstart@%

    %@LW_prowno_0@@
    <button class="no-print" onclick="window.print()">Print</button>
    <center>
      <h3>Trial Balance</h3>
    </center>
    <table>
      <tr>
      	<!--<td><img src="../..//idai/menu/logo_idai.jpeg" width="70px" height="70px"></td>-->
        <td width="600px"><h5>%@LW_PField_Pub_Company@%</h5></td> <td width="110px" style="font-size:13px"><span id="date"></span> *GL403*</td>
      </tr>
    </table>
    <!--<table width="100%">
      <tr class="no-print"><td colspan="3"><button onclick="window.print()">Print</button></td></tr>
      <tr>
        <td width="40%"><h4>%@LW_PField_Pub_Company@%</h4></td>
        <td rowspan="3" style="text-align:center" width="40%"><b><h3>Trial Balance</h3></b></td>
        <td class="text1" width="20%" style="text-align:right">
          <b ><span id="date"></span> *GL400*</b><br/>
          <b >Hal %@LW_PField__page@%</b>
        <td>
      </tr>
    </table>-->
    <script>
      var today = new Date();

      //Isolate the day, the month and the year from the date
      var dd = today.getDate();
      var mm = today.getMonth()+1; //January is 0!
      var yy = today.getFullYear().toString().substr(-2);

      //combine the date elements as mm/dd/yy
      //start by creating a leading zero for single digit days and months
      if(dd<10) {
        dd='0'+dd;
      }

      if(mm<10) {
        mm='0'+mm;
      }

      document.getElementById("date").innerHTML = [dd,mm,yy].join('/');
    </script>
    <table>
      <tr>
        <td class="text2">Period : %@LW_PField_Pub_perDes@%</td>
        <td></td>
      </tr>
    </table>
    <table class="isi text2">
      <tr>
        <th style=width:5%;>Account</th>
        <th style=width:30%;>Description</th>
        <th style=width:5%;>Curn</th>
        <th style=width:15%;>Beginning</th>
        <th style=width:15%;>Debit</th>
        <th style=width:15%;>Credit</th>
        <th style=width:15%;>Balance</th>
        <th style=width:15%;>*</th>
      </tr>
      LW_prowno_0@%

      %@LW_prowno_10@@
      <tr>
        <td>%@LW_PField_s_accno@%</td>
        <td>%@LW_PField_s_descr@%</td>
        <td>%@LW_PField_ca_curncd@%</td>
        <td align="right">%@LW_PField_s_begin@N16/2,N,4,1@%</td>
        <td align="right">%@LW_PField_s_amtdr@N16/2,N,5,1@%</td>
        <td align="right">%@LW_PField_s_amtcr@N16/2,N,6,1@%</td>
        <td align="right">%@LW_PField_s_end@N16/2,N,7,1@%</td>
        <td>%@LW_PField_s_acctyp@%</td>
      </tr>
      LW_prowno_10@%
    </table>
	<table>
    %@LW_prowno_11@@
    <tr>
      <td></td>
      <td colspan="2" class="text2">Total Per %@LW_PField_L0_descr@%</td>
      <td align="right" class="text2"><b>%@LW_PField_L0_begin@N16/2,N,4,1@%</b></td>
      <td align="right" class="text2"><b>%@LW_PField_L0_amtdr@N16/2,N,5,1@%</b></td>
      <td align="right" class="text2"><b>%@LW_PField_L0_amtcr@N16/2,N,6,1@%</b></td>
      <td align="right" class="text2"><b>%@LW_PField_L0_end@N16/2,N,7,1@%</b></td>
    </tr>
    LW_prowno_11@%

    %@LW_prowno_19@@
    <tr>
      <td></td>
      <td colspan="2" class="text2">Total %@LW_PField_L1_descr@%</td>
      <td align="right" class="text2"><b>%@LW_PField_L1_begin@N16/2,N,4,1@%</b></td>
      <td align="right" class="text2"><b>%@LW_PField_L1_amtdr@N16/2,N,5,1@%</b></td>
      <td align="right" class="text2"><b>%@LW_PField_L1_amtcr@N16/2,N,6,1@%</b></td>
      <td align="right" class="text2"><b>%@LW_PField_L1_begin+L1_amtdr-L1_amtcr@N16/2,N,7,1@%</b></td>
    </tr>
    LW_prowno_19@%

    %@LW_prowno_999@@
    <tr>      
      <td align="right" colspan="3" class="text2">Total %@LW_PField_ATrim(Li_descr)@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_Li_begin@n16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_Li_amtdr@N16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_Li_amtcr@N16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_Li_begin-Li_amtdr+Li_amtcr@N16/2,N@%</td>
    </tr> 
    <tr>      
      <td align="right" colspan="3" class="text2">Total %@LW_PField_ATrim(L1_descr)@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_-L1_begin	@n16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_L1_amtdr@N16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_L1_amtcr@N16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField_-L1_begin-L1_amtdr+L1_amtcr@N16/2,N@%</td>
    </tr> 
    <tr>      
      <td align="right" colspan="3" class="text2">Grand Total</td>
      <td style="width:200px" align="right" class="text2"></td>
      <td style="width:200px" align="right" class="text2">%@LW_PField__Gtot_5@N16/2,N@%</td>
      <td style="width:200px" align="right" class="text2">%@LW_PField__Gtot_6@N16/2,N@%</td>
      <td style="width:200px" align="right" class="text2"></td>
    </tr>   
    LW_prowno_999@%

  </table>    
  </body>
</html>
